#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 pixelsize = uTexSize.zw;
vec2 uvm = vUvOriginal;

vec2 noise_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw + rand_frame.xy;
vec4 noiseVal = texture(sampler_noise_lq, noise_uv);

ret.xyz = clamp01(texture( sampler_pw_main,uvm).xyz*vec3(1,1,1) - vec3(.0,.0,.0));
ret.xyz = texture( sampler_pw_main,uvm).xyz;


vec3 rsamp = texture(sampler_pw_main,uvm + (noiseVal.xy-.5)*12*pixelsize).xyz;
if (length(ret.xy - uvm) > length(rsamp.xy - uvm)) {
ret.xy = rsamp.xy;
}

rsamp = texture(sampler_pw_main,uvm + (noiseVal.zw-.5)*48*pixelsize).xyz;
if (length(ret.xy - uvm) > length(rsamp.xy - uvm)) {
ret.xy = rsamp.xy;
}

ret.z = texture(sampler_fw_main,ret.xy).z;

ret.z -= q1*.005;

if (ret.z < .09) {
ret*=0;
}



  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec4 nv = texture(sampler_noise_lq, vUv);
half1 mod = 0;
//ret.z = 0;

vec2 oset = vec2(3,0)*uTexSize.zw;
ret.xy = texture(sampler_main, vUv+oset).xy;
vec2 rsamp = texture(sampler_main, vUv - oset).xy;

vec4 dist = vec4(ret.x,ret.y,rsamp.x,rsamp.y);
dist -= vUv.xyxy;
dist *= dist;
dist += dist.yxwz;
dist = pow(dist,.5);

if (abs(ret.x-rsamp.x) > 0) {
mod = 1;
}

oset = vec2(0,3)*uTexSize.zw;
ret.xy = texture(sampler_main, vUv+oset).xy;
rsamp = texture(sampler_main, vUv - oset).xy;

dist = vec4(ret.x,ret.y,rsamp.x,rsamp.y);
dist -= vUv.xyxy;
dist *= dist;
dist += dist.yxwz;
dist = pow(dist,.5);

if (abs(ret.y-rsamp.y) > 0) {
mod = 1;
}


vec2 uvm = vUv + texture(sampler_main, vUv).xy*100;

uvm = abs(fract((uvm+q12)*.5) - .5)*2 +q10;

uvm = abs(fract((uvm)*.5) - .5)*2;

ret = texture(sampler_rand00, uvm).xyz;

ret *= texture(sampler_main, vUv).z;

mod *= length(ret.xy-vUv);

if (mod.x > 0) {
ret = mod.x*.25;
}



  fragColor = ret;
}
